from functools import wraps
from flask import Flask, session, redirect, url_for, request, render_template_string
from urllib.parse import urlparse, urljoin

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

def is_safe_url(target):
    ref_url = urlparse(request.host_url)
    test_url = urlparse(urljoin(request.host_url, target))
    return test_url.scheme in ('http', 'https') and ref_url.netloc == test_url.netloc

def get_redirect_target():
    for target in request.args.get('next'), request.referrer:
        if not target:
            continue
        if is_safe_url(target):
            return target
    return None

def redirect_back(endpoint='index', **values):
    target = request.form.get('next')
    if not target or not is_safe_url(target):
        target = url_for(endpoint, **values)
    return redirect(target)

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            session['next'] = request.url
            return redirect(url_for('login', next=request.url))
        return f(*args, **kwargs)
    return decorated_function

@app.route('/')
def index():
    if 'user' in session:
        return f'<h1>Welcome {session["user"]}!</h1><a href="/logout">Logout</a><br><a href="/profile">Profile</a><br><a href="/dashboard">Dashboard</a>'
    return '<h1>Home Page</h1><a href="/login">Login</a>'

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        
        if username and password:
            session['user'] = username
            
            next_url = request.form.get('next') or request.args.get('next')
            if next_url and is_safe_url(next_url):
                return redirect(next_url)
            return redirect(url_for('index'))
    
    next_url = request.args.get('next', '')
    
    login_form = f'''
    <h1>Login</h1>
    <form method="post">
        <input type="text" name="username" placeholder="Username" required><br>
        <input type="password" name="password" placeholder="Password" required><br>
        <input type="hidden" name="next" value="{next_url}">
        <button type="submit">Login</button>
    </form>
    '''
    return render_template_string(login_form)

@app.route('/logout')
def logout():
    session.pop('user', None)
    session.pop('next', None)
    return redirect(url_for('index'))

@app.route('/profile')
@login_required
def profile():
    return f'<h1>Profile Page</h1><p>User: {session["user"]}</p><a href="/">Home</a> | <a href="/logout">Logout</a>'

@app.route('/dashboard')
@login_required
def dashboard():
    return f'<h1>Dashboard</h1><p>Welcome to your dashboard, {session["user"]}!</p><a href="/">Home</a> | <a href="/logout">Logout</a>'

